export const getPositionMeaning = (cardId, positionIndex) => {
  const meanings = positionMeaningsData[cardId];
  if (!meanings) return 'ไม่พบความหมายสำหรับไพ่ใบนี้';
  if (positionIndex < 0 || positionIndex >= meanings.length) return 'ไม่พบความหมายสำหรับตำแหน่งนี้';
  return meanings[positionIndex];
};

export default positionMeaningsData;
